1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const INSURANCE_VALUES: Record<string, number> = {
14	  sword: 1000,
15	  amulet: 600,
16	  staff: 800,
17	  potion: 400,
18	  rune: 250,
19	  moonstone: 250,
20	};
21	
22	const DEDUCTIBLE = 100;
23	const CAP_MULTIPLIER = 2;
24	
25	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
26	
27	const CURSE_SURCHARGE_RATE = 0.5;
28	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
29	const HIGH_ENCHANTMENT_THRESHOLD = 5;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	const LOYALTY_YEARS_THRESHOLD = 2;
32	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
33	
34	type Damage = { itemType: string; amount: number };
35	type Incident = { cause: string; damages: Damage[] };
36	type QuoteStep = { op: "quote"; items: Item[] };
37	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
38	type Step = QuoteStep | ClaimStep;
39	
40	type Scenario = {
41	  customer: { yearsWithMHPCO: number };
42	  steps: Step[];
43	};
44	
45	type QuoteResult = { premium: number };
46	type ClaimResult = { payout: number; remainingCap: number };
47	type StepResult = QuoteResult | ClaimResult;
48	
49	const COMPONENT_BLOCK_SIZE = 3;
50	const COMPONENT_BLOCK_PREMIUM = 60;
51	
52	const isComponentBlock = (group: Item[]): boolean => group.length === COMPONENT_BLOCK_SIZE;
53	
54	const sumOfBasePremiums = (items: Item[]): number =>
55	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
56	
57	const groupByType = (items: Item[]): Item[][] =>
58	  Object.values(Object.groupBy(items, (item) => item.type));
59	
60	const basePremiumForGroup = (group: Item[]): number =>
61	  isComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(group);
62	
63	const basePremiumFor = (items: Item[]): number =>
64	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
65	
66	type SurchargeRule = { rate: number; applies: (item: Item) => boolean };
67	
68	const SURCHARGE_RULES: SurchargeRule[] = [
69	  { rate: CURSE_SURCHARGE_RATE, applies: (item) => !!item.cursed },
70	  {
71	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
72	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
73	  },
74	];
75	
76	const surchargeForRule = (items: Item[], rule: SurchargeRule): number =>
77	  items.reduce(
78	    (sum, item) => (rule.applies(item) ? sum + BASE_PREMIUMS[item.type] * rule.rate : sum),
79	    0,
80	  );
81	
82	const surchargesFor = (items: Item[]): number =>
83	  SURCHARGE_RULES.reduce((total, rule) => total + surchargeForRule(items, rule), 0);
84	
85	type Customer = { yearsWithMHPCO: number };
86	type PolicyContext = { customer: Customer; isFollowUp: boolean };
87	
88	type PolicyDiscountRule = { rate: number; applies: (context: PolicyContext) => boolean };
89	
90	const POLICY_DISCOUNT_RULES: PolicyDiscountRule[] = [
91	  {
92	    rate: LOYALTY_DISCOUNT_RATE,
93	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
94	  },
95	  {
96	    rate: FOLLOW_UP_DISCOUNT_RATE,
97	    applies: ({ isFollowUp }) => isFollowUp,
98	  },
99	];
100	
101	const policyDiscountsFor = (base: number, context: PolicyContext): number =>
102	  POLICY_DISCOUNT_RULES.reduce(
103	    (total, rule) => (rule.applies(context) ? total + base * rule.rate : total),
104	    0,
105	  );
106	
107	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
108	  const base = basePremiumFor(items);
109	  const surcharges = surchargesFor(items);
110	  const discounts = policyDiscountsFor(base, { customer, isFollowUp });
111	  return {
112	    premium: Math.ceil(base + surcharges - discounts + base * FIRST_INSURANCE_RATE + PROCESSING_FEE),
113	  };
114	};
115	
116	const isFollowUpStep = (index: number): boolean => index > 0;
117	
118	type Policy = { items: Item[]; remainingCap: number };
119	
120	const insuranceSumFor = (items: Item[]): number =>
121	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
122	
123	const createPolicy = (items: Item[]): Policy => ({
124	  items,
125	  remainingCap: CAP_MULTIPLIER * insuranceSumFor(items),
126	});
127	
128	const payoutForDamage = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE);
129	
130	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
131	  const payout = incident.damages.reduce((sum, damage) => sum + payoutForDamage(damage), 0);
132	  policy.remainingCap -= payout;
133	  return { payout, remainingCap: policy.remainingCap };
134	};
135	
136	export const processScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
137	  const policies: Policy[] = [];
138	  const results: StepResult[] = steps.map((step, index) => {
139	    if (step.op === "quote") {
140	      policies[index] = createPolicy(step.items);
141	      return quotePremium(step.items, customer, isFollowUpStep(index));
142	    }
143	    return processClaim(policies[step.policy], step.incident);
144	  });
145	  return { results };
146	};
